import { test as base } from "vitest";
import { createClient } from "@supabase/supabase-js";
import { seedUser } from "./data-seeding";

if (globalThis.window !== undefined) {
  throw new TypeError(
    "@/lib/test/auth-fixture はサーバー（テスト）でのみ利用可能です。",
  );
}

export interface LoggedInUser {
  userId: string;
  email: string;
  password: string;
  accessToken: string;
}

interface AuthFixtures {
  loggedInUser: LoggedInUser;
}

function uniqueEmail(): string {
  return `fixture-${crypto.randomUUID()}@test.local`;
}

function getSupabaseUrl(): string {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL ?? process.env.SUPABASE_URL;
  if (!url) {
    throw new Error(
      "NEXT_PUBLIC_SUPABASE_URL / SUPABASE_URL のいずれかが設定されている必要があります。",
    );
  }
  return url;
}

function getAnonKey(): string {
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
  if (!key) {
    throw new Error("NEXT_PUBLIC_SUPABASE_ANON_KEY が設定されている必要があります。");
  }
  return key;
}

export const test = base.extend<AuthFixtures>({
  loggedInUser: async ({}, provide) => {
    const email = uniqueEmail();
    const password = "password123";
    const { userId } = await seedUser({ email, password });

    const anonClient = createClient(getSupabaseUrl(), getAnonKey(), {
      auth: { persistSession: false, autoRefreshToken: false },
    });
    const { data, error } = await anonClient.auth.signInWithPassword({
      email,
      password,
    });
    if (error || !data.session) {
      throw error ?? new Error("signInWithPassword が session を返しませんでした");
    }

    await provide({
      userId,
      email,
      password,
      accessToken: data.session.access_token,
    });
  },
});

import * as v from 'valibot'

const supabasePublicConfigSchema = v.object({
    url: v.string(),
    anonKey: v.string(),
})

type SupabasePublicConfig = v.InferOutput<typeof supabasePublicConfigSchema>

const supabasePublicConfig = v.parse(supabasePublicConfigSchema, {
    url: process.env.NEXT_PUBLIC_SUPABASE_URL,
    anonKey: process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY,
})

export function getSupabaseConfig(): SupabasePublicConfig {
    return { ...supabasePublicConfig }
}

