import { createClient, type SupabaseClient } from "@supabase/supabase-js";

if (globalThis.window !== undefined) {
  throw new TypeError(
    "@/lib/test/data-seeding は Service Role キーを使うためサーバー（テスト・seed）でのみ利用可能です。",
  );
}

export interface SeedUserInput {
  email: string;
  password: string;
}

export interface SeededUser {
  userId: string;
}

function getAdminClient(): SupabaseClient {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL ?? process.env.SUPABASE_URL;
  const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (!url) {
    throw new Error(
      "NEXT_PUBLIC_SUPABASE_URL / SUPABASE_URL のいずれかが設定されている必要があります。",
    );
  }
  if (!serviceRoleKey) {
    throw new Error("SUPABASE_SERVICE_ROLE_KEY が設定されている必要があります。");
  }
  return createClient(url, serviceRoleKey, {
    auth: { persistSession: false, autoRefreshToken: false },
  });
}

async function findUserIdByEmail(
  client: SupabaseClient,
  email: string,
): Promise<string | undefined> {
  const { data, error } = await client.auth.admin.listUsers({ perPage: 1000 });
  if (error) throw error;
  return data.users.find((u) => u.email === email)?.id;
}

export async function seedUser(input: SeedUserInput): Promise<SeededUser> {
  const client = getAdminClient();
  const { data, error } = await client.auth.admin.createUser({
    email: input.email,
    password: input.password,
    email_confirm: true,
  });
  if (!error && data.user) {
    return { userId: data.user.id };
  }
  // 既存ユーザーは冪等に扱う
  if (error && /already|exists|registered/i.test(error.message)) {
    const userId = await findUserIdByEmail(client, input.email);
    if (!userId) {
      throw new Error(
        `createUser は失敗したが listUsers でも email=${input.email} を見つけられませんでした: ${error.message}`,
      );
    }
    return { userId };
  }
  throw error ?? new Error("createUser が user を返しませんでした");
}

