1	import type { SupabaseClient } from "@supabase/supabase-js";
2	import { expect, test as base, vi } from "vitest";
3	import { createAuth } from "./index";
4	import { MockAuth } from "./mock-auth";
5	import { SupabaseAuth } from "./supabase-auth";
6	
7	const fakeSupabase = {} as unknown as SupabaseClient;
8	
9	const test = base.extend<{ createAuth: typeof createAuth }>({
10	  createAuth: async ({}, provide) => {
11	    vi.unstubAllEnvs();
12	    await provide(createAuth);
13	  },
14	});
15	
16	test("NEXT_PUBLIC_IS_MOCKED=false の場合は SupabaseAuth を返す", ({
17	  createAuth,
18	}) => {
19	  vi.stubEnv("NEXT_PUBLIC_IS_MOCKED", "false");
20	
21	  const auth = createAuth(fakeSupabase);
22	
23	  expect(auth).toBeInstanceOf(SupabaseAuth);
24	});
25	
26	test("NEXT_PUBLIC_IS_MOCKED=true の場合は MockAuth を返す", ({
27	  createAuth,
28	}) => {
29	  vi.stubEnv("NEXT_PUBLIC_IS_MOCKED", "true");
30	  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_EMAIL", "user@example.com");
31	  vi.stubEnv("NEXT_PUBLIC_MOCK_AUTH_PASSWORD", "secret123");
32	
33	  const auth = createAuth(fakeSupabase);
34	
35	  expect(auth).toBeInstanceOf(MockAuth);
36	});
